import { Anthropic } from '@anthropic-ai/sdk';
import { Vex } from 'vex-sdk';

const anthropic = new Anthropic({ apiKey: 'your-key' });
const vex = new Vex({ apiKey: 'vex-key' });

const message = await anthropic.messages.create({
  model: 'claude-3-5-sonnet-20240620',
  max_tokens: 1024,
  tools: [{ name: 'ehr_navigate', inputSchema: { /* schema */ } }],
  messages: [{ role: 'user', content: 'Navigate to patient chart 12345' }]
});

const verified = await vex.verify({
  spanId: 'ehr-computer-use',
  inputs: message.input,
  outputs: message.content,
  policy: 'healthcare-ehr-safety',
  sensitivity: 'critical'
});

if (verified.passed) {
  console.log('Safe EHR action:', verified.output);
}
